    if len(my_blobs) > 1 and info["threats"]:
        gx = sum(b.pos[0] * mass(b.radius) for b in my_blobs) / total_mass
        gy = sum(b.pos[1] * mass(b.radius) for b in my_blobs) / total_mass
        ux, uy, d = unit(gx - cx, gy - cy)
        fx += ux * 1.8555e-07 * d
        fy += uy * 1.8555e-07 * d

    # ORGAN EV: SOLVED-EVASION override (minimax pursuit/evasion table — the
    # pursuer in the offline solve plays ADVERSARIALLY incl. split strikes,
    # unlike the runtime lookahead's dead-away flee model). Fires only with a
    # capable threat inside EV_RANGE; contributes a force like any organ.
    if CONFIG["EV_ON"] > 0.5 and info["threats"]:
        _t, _d = min(info["threats"], key=lambda td: td[1])
        if _d < CONFIG["EV_RANGE"]:
            _cls = 1 if mass(_t.radius) / 2.0 > mass(my_smallest) * 1.2 else 0
            _sgx = 1.0 if cx <= ARENA_SIZE / 2 else -1.0     # frame: +x away from nearest x-wall
            _sgy = 1.0 if cy <= ARENA_SIZE / 2 else -1.0
            _wx = cx if _sgx > 0 else ARENA_SIZE - cx
            _wy = cy if _sgy > 0 else ARENA_SIZE - cy
            _fdx = (_t.pos[0] - cx) * _sgx
            _fdy = (_t.pos[1] - cy) * _sgy
            try:
                _a = _ev_lookup(_wx, _wy, _fdx, _fdy, _cls, 1 if _cls == 1 else 0)
                _hx, _hy = _EV_DIRS[_a]
                if 0 > 0.5 and _d < CONFIG["EV_RANGE"] * 0.7:
                    _mag = math.hypot(fx, fy) or 1.0     # book OVERRIDES: keep magnitude
                    fx = _hx * _sgx * _mag
                    fy = _hy * _sgy * _mag
                else:
                    _f = CONFIG["W_EV"] * mass(_t.radius) / (_d + EPS)
                    fx += _hx * _sgx * _f
                    fy += _hy * _sgy * _f
            except Exception:
                pass

    # ORGAN VL: solved virus lure — when a bigger blob chases us and a virus
    # is near, the table routes us so the chaser's pursuit crosses the virus
    # (engine pops the LARGEST overlapping blob -> chaser fragments to prey).
    if CONFIG["VL_ON"] > 0.5 and info["threats"] and st.visible_viruses:
        _t, _d = min(info["threats"], key=lambda td: td[1])
        if _d < CONFIG["VL_RANGE"]:
            _v = min(st.visible_viruses, key=lambda v: (v.pos[0]-cx)**2 + (v.pos[1]-cy)**2)
            _vd = math.hypot(_v.pos[0] - cx, _v.pos[1] - cy)
            if _vd < CONFIG["VL_RANGE"]:
                try:
                    _a, _val = _vl_lookup(cx - _v.pos[0], cy - _v.pos[1],
                                          _t.pos[0] - _v.pos[0], _t.pos[1] - _v.pos[1])
                    if _val >= CONFIG["VL_MIN_VAL"]:
                        _hx, _hy = _EV_DIRS[_a]
                        _f = CONFIG["W_VL"] * mass(_t.radius) / (_d + EPS)
                        fx += _hx * _f
                        fy += _hy * _f
                except Exception:
                    pass

    return fx, fy, info



