# Chris 2026-07-16: DEFAULT IS 1E (89% of live rooms have >=1 elite). Drop to
# 0E only once the room is IDENTIFIED as elite-free: no elite sighted by tick
# _MODE_0E_COMMIT. A later sighting still escalates out of 0E permanently.
ELITE_TEAM_IDS = (1, 5, 9, 15, 24, 31, 37, 44, 53, 56, 73, 88)          # empty in gym -> tally code never runs
_OUR_TEAM_ID = 35            # codegen may override; anomaly lever needs it
_MODE_CUTOVER_UTC = "2026-07-19T23:00:00"
_MODE_0E_COMMIT = 150
_BASE_CONFIG = dict(CONFIG)
_SEEN_ELITES = set()
_MODE = [1]
_MODE_TICKS = [0]

def _mode_for(tally):
    # Chris 2026-07-17: final mode turns on at 3E+ (the separate 3E model is
    # retired; the finals-world champion plays every elite-dense room)
    # v20 (Chris 2026-07-19): 4471 base (won 500-room 1E head-to-head).
    # tally 2-3 -> 2E farming chassis; >=4 -> champion 4628; 7E/3712
    # ONLY on team-id anomaly or 23:00Z cutover (real-finals signals).
    return 3 if tally >= 4 else 2 if tally >= 2 else 1

def _apply_mode(m):
    if m == _MODE[0]:
        return
    _MODE[0] = m
    CONFIG.clear()
    CONFIG.update(_BASE_CONFIG)
    CONFIG.update(MODE_OVERLAYS.get(m, {}))
    try:
        print(f"[mode] tick {_MODE_TICKS[0]}: switched to {m}E "
              f"(elites seen: {len(_SEEN_ELITES)})", flush=True)
    except Exception:
        pass

try:
    from datetime import datetime as _md, timezone as _mtz
    _FORCE_7E = _md.now(_mtz.utc).strftime("%Y-%m-%dT%H:%M:%S") >= _MODE_CUTOVER_UTC
except Exception:
    _FORCE_7E = False

# Boot line (once per match, ship only — silent in gym where overlays/ids are
# empty): current UTC time, whether the 7E final mode is on, and time until it is.
if ELITE_TEAM_IDS or MODE_OVERLAYS[7]:
    try:
        _now = _md.now(_mtz.utc)
        _cut = _md.strptime(_MODE_CUTOVER_UTC, "%Y-%m-%dT%H:%M:%S").replace(tzinfo=_mtz.utc)
        _left = (_cut - _now).total_seconds()
        _eta = "ON" if _left <= 0 else f"armed, on in {int(_left // 3600)}h{int(_left % 3600 // 60):02d}m"
        print(f"[boot] {_now.strftime('%Y-%m-%d %H:%M:%S')}Z | final mode 7E: {_eta} "
              f"| cutover {_MODE_CUTOVER_UTC}Z", flush=True)
    except Exception:
        pass
if _FORCE_7E and (MODE_OVERLAYS[7] or ELITE_TEAM_IDS):
    _apply_mode(7)

_MODE_ID_CHECKED = [False]

def _mode_tick(st):
    """Per-tick elite tally + mode selection (Chris 2026-07-17 three-lever
    design): START in 1E. Tally 2 -> 2E, tally>=3 -> FINAL. Escalate-only.
    Drop to 0E only when the room is identified elite-free: zero sightings
    for the first _MODE_0E_COMMIT ticks; 0E abandoned permanently on first
    contact. FINAL also forces on a team-id anomaly in game_started (our id
    changed, or all ids 0..7); the time backstop is boot-only (never checked
    per-tick — Chris 2026-07-17). No-op when ELITE_TEAM_IDS is empty (gym).
    Once FINAL, behavior stays PINNED; the tally keeps logging — telemetry."""
    global _FORCE_7E
    if not ELITE_TEAM_IDS:
        return
    try:
        _MODE_TICKS[0] += 1
        # LEVER 3 — team-id anomaly (checked until game_started is found).
        # Bots receive PUBLIC game_started: other players carry NO team_id,
        # but `you` is our full PlayerModel incl. team_id (verified in
        # helper/state_mutator + lib event models 2026-07-17). A finals
        # re-seed (ids 0-7 or any remap) necessarily changes OUR id != 35.
        if not _MODE_ID_CHECKED[0] and _MODE_TICKS[0] <= 60:
            _gs = None
            for _e in getattr(st, "event_history", [])[:40]:
                if getattr(_e, "event_type", "") in (
                        "public_event_game_started", "event_game_started"):
                    _gs = _e
                    break
            if _gs is not None:
                _MODE_ID_CHECKED[0] = True
                _mine = None
                _you = getattr(_gs, "you", None)
                if _you is not None:
                    _mine = getattr(_you, "team_id", None)
                else:
                    _mypid = st.me.player_id
                    for _p in (getattr(_gs, "players", None) or []):
                        if isinstance(_p, dict):
                            _pid, _tid = _p.get("player_id"), _p.get("team_id")
                        else:
                            _pid = getattr(_p, "player_id", None)
                            _tid = getattr(_p, "team_id", None)
                        if _pid == _mypid:
                            _mine = _tid
                            break
                if _mine is not None and _mine != _OUR_TEAM_ID and not _FORCE_7E:
                    _FORCE_7E = True
                    try:
                        print(f"[mode] tick {_MODE_TICKS[0]}: TEAM-ID ANOMALY "
                              f"(our team_id={_mine} != {_OUR_TEAM_ID}) "
                              f"-> FINAL MODE", flush=True)
                    except Exception:
                        pass
                    _apply_mode(7)
        # LEVER 2 — elite tally (top-10 set, 3+ -> FINAL via _mode_for)
        _before = len(_SEEN_ELITES)
        for _b in st.visible_blobs:
            _t = getattr(_b, "team_id", None)
            if _t in ELITE_TEAM_IDS:
                _SEEN_ELITES.add(_t)
        if len(_SEEN_ELITES) > _before:
            try:
                print(f"[mode] tick {_MODE_TICKS[0]}: identified elites "
                      f"{sorted(_SEEN_ELITES)} (tally {len(_SEEN_ELITES)})", flush=True)
            except Exception:
                pass
        if _FORCE_7E:
            return
        if _SEEN_ELITES:
            _apply_mode(_mode_for(len(_SEEN_ELITES)))
        elif _MODE_TICKS[0] >= _MODE_0E_COMMIT and _MODE[0] == 1:
            _apply_mode(0)
    except Exception:
        pass
# ============ end MODE SWITCH ============

