import base64 as _vl_b64
_VL_POL = _vl_b64.b85decode(_VL_POL_B85)
_VL_VAL = _vl_b64.b85decode(_VL_VAL_B85)
def _vl_bucket(v, edges):
    lo, hi = 0, len(edges) - 1
    if v <= edges[0]: return 0
    if v >= edges[hi]: return hi
    while hi - lo > 1:
        mid = (lo + hi) // 2
        if edges[mid] <= v: lo = mid
        else: hi = mid
    return lo
def _vl_lookup(ox, oy, px, py):
    i = ((_vl_bucket(ox, _VL_AX) * 9 + _vl_bucket(oy, _VL_AX)) * 9
         + _vl_bucket(px, _VL_AX)) * 9 + _vl_bucket(py, _VL_AX)
    b = _VL_POL[i >> 1]
    a = (b >> 4) if (i & 1) else (b & 15)
    return a & 7, _VL_VAL[i]
