import base64 as _pb_b64
_PB_SPLIT = _pb_b64.b85decode(_PB_SPLIT_B85)
_PB_GUARD = _pb_b64.b85decode(_PB_GUARD_B85)
def _pb_bucket(v, edges):
    lo, hi = 0, len(edges) - 1
    if v <= edges[0]: return 0
    if v >= edges[hi]: return hi
    while hi - lo > 1:
        mid = (lo + hi) // 2
        if edges[mid] <= v: lo = mid
        else: hi = mid
    return lo
def _pb_split_h(M, tm, d):
    idx = (_pb_bucket(M, _PB_M_EDGES) * 24 + _pb_bucket(tm, _PB_T_EDGES)) * 28 + _pb_bucket(d, _PB_D_EDGES)
    b = _PB_SPLIT[idx >> 1]
    return (b >> 4) if (idx & 1) else (b & 15)
def _pb_virus_guard(M, rm):
    return _PB_GUARD[_pb_bucket(M, _PB_M_EDGES) * 24 + _pb_bucket(rm, _PB_T_EDGES)]
