# Dead code unless CONFIG["PLAN_ON"] > 0.5. The governor is a safety layer,
# not a gene: cumulative planning time is metered and the organ self-disables
# for the rest of the match past _PLAN_BUDGET_S (cumulative engine budget is
# 8s/match; bans score 0 — nothing the planner buys is worth a ban).
import time as _ptime
_PLAN_BUDGET_S = 3.5
_PLAN_STATE = [0.0, 0, 0]    # [cumulative seconds (-1 = tripped), calls, overrides]
import atexit as _plan_atexit
@_plan_atexit.register
def _plan_report():
    try:
        if _PLAN_STATE[1] > 0:
            print(f"[plan] telemetry: calls {_PLAN_STATE[1]}, overrides {_PLAN_STATE[2]}, "
                  f"time {'TRIPPED' if _PLAN_STATE[0] < 0 else f'{_PLAN_STATE[0]*1000:.0f}ms'}", flush=True)
    except Exception:
        pass

def _plan_candidates(st, tracker, info, ux0, uy0, cx, cy, my_large_r):
    """Structured first actions (planner v2 per 2026-07-16 review): reactive,
    turns, reversal, escape, prey intercept, food centroid, wall tangents."""
    cands = [(ux0, uy0)]
    base = math.atan2(uy0, ux0)
    for off in (0.52, -0.52, 1.05, -1.05, 1.57, -1.57, math.pi):
        a = base + off
        cands.append((math.cos(a), math.sin(a)))
    if info["threats"]:
        t, _d = min(info["threats"], key=lambda td: td[1])
        ex, ey, m = unit(cx - t.pos[0], cy - t.pos[1])
        if m > EPS: cands.append((ex, ey))
        # EV book heading as a planner CANDIDATE (harness verdict 2026-07-16:
        # book-guided MPC beats field +26%; raw override loses — the book
        # proposes, the rollout disposes)
        if CONFIG["EV_ON"] > 0.5:
            try:
                _sgx = 1.0 if cx <= ARENA_SIZE / 2 else -1.0
                _sgy = 1.0 if cy <= ARENA_SIZE / 2 else -1.0
                _cls = 1        # conservative: treat candidate threat as split-capable
                _a = _ev_lookup(cx if _sgx > 0 else ARENA_SIZE - cx,
                                cy if _sgy > 0 else ARENA_SIZE - cy,
                                (t.pos[0] - cx) * _sgx, (t.pos[1] - cy) * _sgy, _cls, 1)
                _hx, _hy = _EV_DIRS[_a]
                cands.append((_hx * _sgx, _hy * _sgy))
            except Exception:
                pass
    if info["prey"]:
        p, pd = min(info["prey"], key=lambda pd: pd[1])
        try:
            ixp, iyp = tracker.predict(p, min(pd / max(_la_speed(my_large_r), 0.05), 10))
        except Exception:
            ixp, iyp = p.pos
        px, py, m = unit(ixp - cx, iyp - cy)
        if m > EPS: cands.append((px, py))
    if st.visible_food:
        fs = sorted(st.visible_food, key=lambda f: (f.pos[0]-cx)**2 + (f.pos[1]-cy)**2)[:12]
        fxm = sum(f.pos[0] for f in fs) / len(fs); fym = sum(f.pos[1] for f in fs) / len(fs)
        gx, gy, m = unit(fxm - cx, fym - cy)
        if m > EPS: cands.append((gx, gy))
    wmar = my_large_r + 2.0
    if cx < wmar or cx > ARENA_SIZE - wmar:
        cands.append((0.0, 1.0)); cands.append((0.0, -1.0))
    if cy < wmar or cy > ARENA_SIZE - wmar:
        cands.append((1.0, 0.0)); cands.append((-1.0, 0.0))
    out = []
    for u in cands:                     # dedup within ~15 degrees
        if all(u[0]*v[0] + u[1]*v[1] < 0.966 for v in out):
            out.append(u)
    return out[:14]

def _plan_hz_step(px, py, tracks, my_large_r, my_frag, bank_band, speed):
    """One-step conditional hazard at a simulated position (mined table).
    Returns (h1, support). Table stores 20-tick window hazard -> converted."""
    if not tracks:
        return 0.0, 0.0
    tx, ty, vx, vy, er, tm = min(tracks, key=lambda t: (t[0]-px)**2 + (t[1]-py)**2)
    d = math.hypot(tx - px, ty - py)
    cap = _hz_band(d - er, _HZ_CAP_E)
    half = tm / 2.0
    spl = _hz_band(d - (2.0 * math.sqrt(half) + 4.0), _HZ_SPL_E) if half >= mass(my_large_r) * 1.2 * 0.25 else len(_HZ_SPL_E)
    rel = _la_speed(math.sqrt(tm)) - speed
    ttc = _hz_band(d / rel, _HZ_TTC_E) if rel > 0.01 else len(_HZ_TTC_E)
    wallx = min(px, ARENA_SIZE - px); wally = min(py, ARENA_SIZE - py)
    wcls = (wallx < 6) + (wally < 6)
    cone = sum(1 for k in range(8)
               if not ((math.cos(k * 0.785) < -0.3 and wallx < 4) or
                       (math.sin(k * 0.785) < -0.3 and wally < 4)))
    second = 1 if len(tracks) > 1 else 0
    d20, sup = _hz_lookup(cap, spl, wcls, my_frag, ttc, second, cone, bank_band)
    h1 = 1.0 - (1.0 - min(d20, 0.995)) ** (1.0 / 20.0)
    return h1, sup

def _plan_rollout(px, py, u, h0, h1, foods, taken, tracks, my_large_r, speed, w_thr, w_wall,
                  hz_ctx=None):
    """Simulate ticks h0..h1 along heading u. hz_ctx = (frag, bank_band, w_hz,
    death_cost) enables mined-hazard survival discounting (HZ_ON)."""
    score = 0.0
    surv = 1.0
    dead = False
    lo = my_large_r; hi = ARENA_SIZE - my_large_r
    for h in range(h0, h1 + 1):
        px = min(max(px + u[0] * speed, lo), hi)
        py = min(max(py + u[1] * speed, lo), hi)
        for fi, fp in foods:
            if fi not in taken and (fp[0]-px)**2 + (fp[1]-py)**2 < my_large_r * my_large_r:
                taken.add(fi); score += 1.0 * surv
        for tx, ty, vx, vy, er, tm in tracks:
            qx, qy = tx + vx * h, ty + vy * h
            d2 = (qx - px)**2 + (qy - py)**2
            if d2 < er * er:
                score -= 1000.0 / h
                dead = True
                break
            score -= w_thr * tm / ((d2 + 1.0))
        if dead: break
        if hz_ctx is not None:
            _frag, _bank, _whz, _dcost = hz_ctx
            _h1s, _sup = _plan_hz_step(px, py, tracks, my_large_r, _frag, _bank, speed)
            surv *= (1.0 - _sup * _whz * _h1s)
        if px <= lo + 0.01 or px >= hi - 0.01 or py <= lo + 0.01 or py >= hi - 0.01:
            score -= w_wall
    if hz_ctx is not None and not dead:
        _frag, _bank, _whz, _dcost = hz_ctx
        score -= (1.0 - surv) * _dcost
    return score, px, py, taken, dead

def _plan_heading(st, tracker, info, fx, fy, my_large_r, my_small_m):
    ux0, uy0, m0 = unit(fx, fy)
    if m0 <= EPS:
        return fx, fy
    H = max(2, int(CONFIG["PLAN_H"]))
    speed = _la_speed(my_large_r)          # ENGINE law (divisive), not the heuristic
    cx, cy = st.me.x, st.me.y
    tracks = []
    for t, _d in info["threats"]:
        vx, vy = tracker.velocity.get((t.player_id, t.blob_id), (0.0, 0.0))
        tracks.append((t.pos[0], t.pos[1], vx, vy, t.radius, mass(t.radius)))
    foods = [(i, f.pos) for i, f in enumerate(
        sorted(st.visible_food, key=lambda f: (f.pos[0]-cx)**2 + (f.pos[1]-cy)**2)[:36])]
    w_thr = CONFIG["W_PLAN_THREAT"]; w_wall = CONFIG["W_PLAN_WALL"]
    hz_ctx = None
    if CONFIG["HZ_ON"] > 0.5:
        _bank_m = mass(my_large_r) + my_small_m
        _bank_band = _hz_band(_bank_m, _HZ_BANK_E)
        _frag = 0
        _dcost = CONFIG["W_HZ_DEATHCOST"] * (1.0 + _bank_m / 40.0)
        hz_ctx = (_frag, _bank_band, CONFIG["W_HZ"], _dcost)
    w_food = CONFIG["W_PLAN_FOOD"]; w_align = CONFIG["W_PLAN_ALIGN"]
    cands = _plan_candidates(st, tracker, info, ux0, uy0, cx, cy, my_large_r)
    hmid = max(1, H // 2)
    # phase 1: first action to mid-horizon
    beam = []
    for u in cands:
        s, px, py, taken, dead = _plan_rollout(cx, cy, u, 1, hmid, foods, set(),
                                               tracks, my_large_r, speed, w_thr, w_wall,
                                               hz_ctx=hz_ctx)
        s += w_align * (u[0]*ux0 + u[1]*uy0)
        beam.append((s, u, px, py, taken, dead))
    beam.sort(key=lambda b: -b[0])
    beam = beam[:max(2, int(CONFIG.get("PLAN_BEAM", 4)))]
    # phase 2: one mid-horizon heading change (continue / turn +-60)
    best_s, best_u = -1e18, (ux0, uy0)
    for s1, u, px, py, taken, dead in beam:
        if dead:
            if s1 > best_s: best_s, best_u = s1, u
            continue
        ba = math.atan2(u[1], u[0])
        for off in (0.0, 1.05, -1.05):
            a = ba + off
            u2 = (math.cos(a), math.sin(a))
            s2, _, _, _, _ = _plan_rollout(px, py, u2, hmid + 1, H, foods, set(taken),
                                           tracks, my_large_r, speed, w_thr, w_wall,
                                           hz_ctx=hz_ctx)
            tot = s1 + s2
            if tot > best_s:
                best_s, best_u = tot, u
    return best_u

# ============ PLANCORE (2026-07-17) — planning as the core, gene-gated ============
# Candidate 0 = reactive action now + reactive continuation; alternatives
# differ ONLY in the first action, share the same continuation policy. The
# baseline is scored outside pruning (there is no pruning) and wins unless an
# alternative dominates lexicographically: risk <= baseline + PC_RISK_EPS AND
# value > baseline + PC_MARGIN. Objective = engine events (mass captured,
# pieces lost, terminal mined-hazard bank risk). PC_ON=0 => bit-identical.
_PC_STATE = [0.0, 0, 0, 0]   # [seconds (-1=tripped), calls, overrides, split_overrides]
_PC_BUDGET_S = 1.5   # Chris 2026-07-17: raised 3.0->6.0 — non-planner stack uses
                     # ~0.15s locally (~0.6s on a 4x-slower server CPU), so 6s
                     # planner cap still leaves >1.4s margin vs the 8s ban line;
                     # trip still degrades to pure reactive, never bans

def _pc_react(px, py, foods, taken, threats, my_r, h):
    """Continuation policy: light reactive heading at a simulated state.
    Repels THREATS only (prey are not fled from — P0 fix)."""
    fx = fy = 0.0
    for fi, fp, fm in foods:
        if fi in taken: continue
        dx, dy = fp[0] - px, fp[1] - py
        w = 1.0 / (dx * dx + dy * dy + 0.5)
        fx += dx * w; fy += dy * w
    for tx, ty, ix, iy, er, tm in threats:
        qx, qy = tx + ix * h, ty + iy * h
        dx, dy = px - qx, py - qy
        d2 = dx * dx + dy * dy + 0.5
        w = 8.0 * tm / d2
        d = math.sqrt(d2)
        fx += dx / d * w; fy += dy / d * w
    m = 1.10337e-06
    if px < m + my_r: fx += (m + my_r - px) * 0.8
    if px > ARENA_SIZE - m - my_r: fx -= (px - (ARENA_SIZE - m - my_r)) * 0.8
    if py < m + my_r: fy += (m + my_r - py) * 0.8
    if py > ARENA_SIZE - m - my_r: fy -= (py - (ARENA_SIZE - m - my_r)) * 0.8
    d = math.hypot(fx, fy)
    return (fx / d, fy / d) if d > 1e-9 else (0.0, 0.0)

_PC_FOOD_MASS = 0.15 * 0.15         # engine FOOD_RADIUS = 0.15
_PC_DECAY = 0.002                    # engine MASS_DECAY_RATE per tick
_PC_SPLIT_MIN = 2.0                  # engine SPLIT_MIN_MASS
_PC_SPLIT_CD = 18                    # engine SPLIT_COOLDOWN_FRAMES
_PC_EJECT = 1.6                      # engine SPLIT_EJECT_SPEED

def _pc_rollout(blobs0, foods, threats, preys, first_u, first_split, H, hz_on, death_cost):
    """Engine-true rollout (P0 repairs 2026-07-17): split = EVERY eligible
    blob, child eject 1.6 with drag 0.82 integrated like _move_blob; food
    mass 0.0225 added to the eating blob; 0.2%/tick decay; prey separated
    from threats. blobs: [x, y, m, cd, evx, evy]. Returns (value, risk, blobs)."""
    blobs = [b[:] for b in blobs0]
    threats = list(threats)
    preys = list(preys)
    if first_split:
        adds = []
        for b in blobs:
            if len(blobs) + len(adds) >= 16: break
            if b[2] < _PC_SPLIT_MIN: continue
            half = b[2] / 2.0
            cr = math.sqrt(half)
            b[2] = half
            b[3] = _PC_SPLIT_CD
            adds.append([b[0] + first_u[0] * (cr + cr + 0.01),
                         b[1] + first_u[1] * (cr + cr + 0.01),
                         half, _PC_SPLIT_CD,
                         first_u[0] * _PC_EJECT, first_u[1] * _PC_EJECT])
        blobs.extend(adds)
    taken = set()
    start_mass = sum(b[2] for b in blobs)
    gained = 0.0
    lost = 0.0
    for h in range(1, H + 1):
        if h == 1:
            u = first_u
        else:
            tm_all = max(1e-9, sum(b[2] for b in blobs))
            cxm = sum(b[0] * b[2] for b in blobs) / tm_all
            cym = sum(b[1] * b[2] for b in blobs) / tm_all
            rr = math.sqrt(max((b[2] for b in blobs), default=1.0))
            u = _pc_react(cxm, cym, foods, taken, threats, rr, h)
        for b in blobs:
            r = math.sqrt(b[2])
            if u != (0.0, 0.0):
                sp = _la_speed(r)
                b[0] += u[0] * sp; b[1] += u[1] * sp
            b[0] += b[4]; b[1] += b[5]
            b[4] *= 0.82; b[5] *= 0.82
            if abs(b[4]) < 1e-4: b[4] = 0.0
            if abs(b[5]) < 1e-4: b[5] = 0.0
            b[0] = min(max(b[0], r), ARENA_SIZE - r)
            b[1] = min(max(b[1], r), ARENA_SIZE - r)
            if b[3] > 0: b[3] -= 1
            b[2] *= (1.0 - _PC_DECAY)
            for fi, fp, fm in foods:
                if fi not in taken and (fp[0]-b[0])**2 + (fp[1]-b[1])**2 < b[2]:
                    taken.add(fi); b[2] += fm; gained += fm
        for ti, (tx, ty, ix, iy, er, tm) in enumerate(threats):
            qx, qy = tx + ix * h, ty + iy * h
            for b in list(blobs):
                if tm >= b[2] * 1.2 and (qx-b[0])**2 + (qy-b[1])**2 <= er * er:
                    lost += b[2]
                    blobs.remove(b)
        eaten = []
        for pi, (qx0, qy0, ix, iy, pr, pm) in enumerate(preys):
            qx, qy = qx0 + ix * h, qy0 + iy * h
            for b in blobs:
                if b[2] >= pm * 1.2 and (qx-b[0])**2 + (qy-b[1])**2 <= b[2]:
                    b[2] += pm
                    gained += pm
                    eaten.append(pi)
                    break
        if eaten:
            preys = [t for j, t in enumerate(preys) if j not in eaten]
        if not blobs:
            return gained - lost - death_cost, 1.0, blobs
    value = gained - lost
    risk = min(1.0, lost / max(1e-9, start_mass))
    if hz_on and blobs:
        bi = max(range(len(blobs)), key=lambda i: blobs[i][2])
        bx, by, bm = blobs[bi][0], blobs[bi][1], blobs[bi][2]
        term_threats = [(tx + ix * H, ty + iy * H, 0.0, 0.0, er, tm)
                        for tx, ty, ix, iy, er, tm in threats]
        frag = 0 if len(blobs) == 1 else (1 if len(blobs) <= 3 else 2)
        bank_band = _hz_band(sum(b[2] for b in blobs), _HZ_BANK_E)
        h1s, sup = _plan_hz_step(bx, by, term_threats, math.sqrt(bm), frag, bank_band,
                                 _la_speed(math.sqrt(bm)))
        d20 = 1.0 - (1.0 - h1s) ** 20.0
        value -= CONFIG["W_HZ"] * sup * d20 * death_cost
        risk = max(risk, sup * d20)
    return value, risk, blobs

def _pc_choose(st, tracker, info, fx, fy, split, my_blobs, total_m):
    """PLANCORE decision: returns (fx, fy, split). Evaluated action ==
    executed action (P0 fix): every candidate carries the exact split flag it
    would return, and split candidates are pre-checked against the SAME LA
    gate that runs downstream, so the final move is always the one simulated."""
    ux0, uy0, m0 = unit(fx, fy)
    if m0 <= EPS:
        return fx, fy, split
    H = max(2, min(5, int(CONFIG["PC_H"])))
    cx, cy = st.me.x, st.me.y
    blobs0 = [[b.pos[0], b.pos[1], mass(b.radius), getattr(b, "merge_cooldown", 0), 0.0, 0.0]
              for b in my_blobs]
    if not blobs0:
        return fx, fy, split
    foods = [(i, f.pos, _PC_FOOD_MASS) for i, f in enumerate(
        sorted(st.visible_food, key=lambda f: (f.pos[0]-cx)**2 + (f.pos[1]-cy)**2)[:30])]
    def track_of(t):
        ii = tracker.intent_dir.get(t.player_id)
        if ii is not None:
            spd = _la_speed(t.radius)
            return (t.pos[0], t.pos[1], ii[0] * spd, ii[1] * spd, t.radius, mass(t.radius))
        vx, vy = tracker.velocity.get((t.player_id, t.blob_id), (0.0, 0.0))
        return (t.pos[0], t.pos[1], vx, vy, t.radius, mass(t.radius))
    threats = [track_of(t) for t, _d in info["threats"]]
    preys = [track_of(p) for p, _d in info["prey"]]
    death_cost = total_m + CONFIG["PC_DEATH_EXTRA"]
    hz_on = CONFIG["HZ_ON"] > 0.5

    _mb = [(b.pos[0], b.pos[1], mass(b.radius)) for b in my_blobs]
    _vir = [(v.pos[0], v.pos[1]) for v in st.visible_viruses]
    _thr = [(t.pos[0], t.pos[1], mass(t.radius)) for t, _d in info["threats"]]
    def la_ok(u):
        try:
            _tgt = None
            if info["prey"]:
                _pp = min(info["prey"], key=lambda q: q[1])[0]
                _tgt = (_pp.pos[0], _pp.pos[1], mass(_pp.radius))
            return _la_gate_split(u[0], u[1], _mb, _vir, _thr, _tgt)
        except Exception:
            return False

    base_v, base_r, _bb = _pc_rollout(blobs0, foods, threats, preys, (ux0, uy0), split,
                                      H, hz_on, death_cost)
    cands = []
    for k in range(8):
        a = k * math.pi / 4.0
        u = (math.cos(a), math.sin(a))
        if u[0] * ux0 + u[1] * uy0 > 0.985:
            continue
        cands.append((u, split))         # heading alternatives KEEP the incoming split
    pu = None
    if info["prey"]:
        pp, pd = min(info["prey"], key=lambda q: q[1])
        try:
            big_r = math.sqrt(max(b[2] for b in blobs0))
            ixp, iyp = tracker.predict(pp, min(pd / max(_la_speed(big_r), 0.05), 10))
        except Exception:
            ixp, iyp = pp.pos
        v = unit(ixp - cx, iyp - cy)
        if v[2] > EPS:
            pu = (v[0], v[1])
            cands.append((pu, split))
    if CONFIG["PC_SPLIT"] > 0.5 and not split:
        for u in ([(ux0, uy0)] + ([pu] if pu is not None else [])):
            if la_ok(u):
                cands.append((u, True))
    best_v, best = base_v, None
    for u, sp_flag in cands[:14]:
        v, r, _bb = _pc_rollout(blobs0, foods, threats, preys, u, sp_flag, H, hz_on, death_cost)
        if r <= base_r + CONFIG["PC_RISK_EPS"] and v > best_v + CONFIG["PC_MARGIN"]:
            best_v, best = v, (u, sp_flag)
    if best is None:
        return fx, fy, split
    _PC_STATE[2] += 1
    if best[1] and not split:
        _PC_STATE[3] += 1
    return best[0][0], best[0][1], best[1]

import atexit as _pc_atexit
@_pc_atexit.register
def _pc_report():
    try:
        if _PC_STATE[1] > 0:
            print(f"[plancore] calls {_PC_STATE[1]}, overrides {_PC_STATE[2]}, "
                  f"split-overrides {_PC_STATE[3]}, time "
                  f"{'TRIPPED' if _PC_STATE[0] < 0 else f'{_PC_STATE[0]*1000:.0f}ms'}", flush=True)
    except Exception:
        pass
# ============ end PLANCORE ============

# ============ LOOKAHEAD VETO GATE (2026-07-15) — inlined, engine-faithful ============
# Simulates split-half trajectories (parent + ballistic child) a few ticks ahead to
# VETO unsafe splits the reactive force field cannot see. Dead code unless
# CONFIG["LOOKAHEAD_ON"] > 0.5, so bit-exact-neutral when off.
_LA_BASE_SPEED = 1.1; _LA_SPD_FACTOR = 0.08; _LA_MIN_SPEED = 0.25
_LA_SPLIT_MIN_MASS = 2.0; _LA_EJECT = 1.6; _LA_DRAG = 0.82; _LA_EAT = 1.2
_LA_VIRUS_POP = (1.5 ** 2) * 1.2  # 2.7: half-mass must exceed this to pop

def _la_speed(r):
    return max(_LA_MIN_SPEED, _LA_BASE_SPEED / (1.0 + r * _LA_SPD_FACTOR))

def _la_unit(dx, dy):
    d = math.hypot(dx, dy)
    return (dx / d, dy / d) if d > 1e-9 else (0.0, 0.0)

def _la_step(x, y, vx, vy, r, sx, sy):
    sp = _la_speed(r)
    x += sx * sp + vx; y += sy * sp + vy
    vx *= _LA_DRAG; vy *= _LA_DRAG
    if abs(vx) < 1e-4: vx = 0.0
    if abs(vy) < 1e-4: vy = 0.0
    return min(60.0, max(0.0, x)), min(60.0, max(0.0, y)), vx, vy

def _la_hits_virus(x, y, r, vx, vy, sx, sy, viruses, horizon):
    for _ in range(horizon):
        for (vx0, vy0) in viruses:
            if (x - vx0) ** 2 + (y - vy0) ** 2 <= r * r:
                return True
        x, y, vx, vy = _la_step(x, y, vx, vy, r, sx, sy)
    return False

def _la_virus_veto(my_blobs, sx, sy, viruses, horizon):
    if not viruses: return False
    for (bx, by, m) in my_blobs:
        if m < _LA_SPLIT_MIN_MASS: continue
        half = m / 2.0
        if half <= _LA_VIRUS_POP: continue
        hr = math.sqrt(half)
        if _la_hits_virus(bx, by, hr, 0.0, 0.0, sx, sy, viruses, horizon): return True
        cx = bx + sx * (hr + hr); cy = by + sy * (hr + hr)
        if _la_hits_virus(cx, cy, hr, sx * _LA_EJECT, sy * _LA_EJECT, sx, sy, viruses, horizon): return True
    return False

def _la_miss_veto(my_blobs, sx, sy, threats, horizon):
    if not threats: return False
    for (bx, by, m) in my_blobs:
        if m < _LA_SPLIT_MIN_MASS: continue
        cm = m / 2.0; cr = math.sqrt(cm)
        cx = bx + sx * (cr + cr); cy = by + sy * (cr + cr)
        evx = sx * _LA_EJECT; evy = sy * _LA_EJECT
        for (tx, ty, tm) in threats:
            if tm <= cm * _LA_EAT: continue
            hx, hy, hvx, hvy = cx, cy, evx, evy; ex, ey = tx, ty
            tr = math.sqrt(tm); ts = _la_speed(tr)
            for _ in range(horizon):
                ux, uy = _la_unit(hx - ex, hy - ey)
                ex += ux * ts; ey += uy * ts
                hx, hy, hvx, hvy = _la_step(hx, hy, hvx, hvy, cr, sx, sy)
                if (hx - ex) ** 2 + (hy - ey) ** 2 <= tr * tr: return True
    return False

def _la_attack_lands(bx, by, m, target, sx, sy, horizon):
    tx, ty, tm = target
    cm = m / 2.0
    if cm <= tm * _LA_EAT: return False
    cr = math.sqrt(cm)
    cx = bx + sx * (cr + cr); cy = by + sy * (cr + cr)
    vx = sx * _LA_EJECT; vy = sy * _LA_EJECT
    tr = math.sqrt(tm); ts = _la_speed(tr)
    for _ in range(horizon):
        fx, fy = _la_unit(tx - bx, ty - by)
        tx += fx * ts; ty += fy * ts
        cx, cy, vx, vy = _la_step(cx, cy, vx, vy, cr, sx, sy)
        if (cx - tx) ** 2 + (cy - ty) ** 2 <= cr * cr: return True
    return False

def _la_gate_split(fx, fy, my_blobs, viruses, threats, target):
    """Returns False if the proposed split should be vetoed. CONFIG-driven sub-toggles."""
    sx, sy = _la_unit(fx, fy)
    if sx == 0.0 and sy == 0.0: return True
    h = int(round(CONFIG.get("LA_HORIZON", 5.0)))
    if CONFIG.get("LA_VIRUS", 1.0) > 0.5 and _la_virus_veto(my_blobs, sx, sy, viruses, h): return False
    if CONFIG.get("LA_MISS", 1.0) > 0.5 and _la_miss_veto(my_blobs, sx, sy, threats, h): return False
    if CONFIG.get("LA_ATTACK", 1.0) > 0.5 and target is not None and my_blobs:
        bx, by, m = my_blobs[0]
        if not _la_attack_lands(bx, by, m, target, sx, sy, h): return False
    return True
# ============ end LOOKAHEAD ============

def _clip(v: float, lo: float = -1.0, hi: float = 1.0) -> float:
    return max(lo, min(hi, v))


def _sigmoid(v: float) -> float:
    v = max(-20.0, min(20.0, v))
    return 2.0 / (1.0 + math.exp(-v)) - 1.0


def _arch_op(op: int, a: float, b: float, k: float, bias: float) -> float:
    if op == 0:
        z = a
    elif op == 1:
        z = a + b
    elif op == 2:
        z = a - b
    elif op == 3:
        z = a * b
    elif op == 4:
        z = max(a, b)
    elif op == 5:
        z = min(a, b)
    elif op == 6:
        z = _sigmoid(k * a + bias)
    elif op == 7:
        z = 1.0 if a > b else -1.0
    elif op == 8:
        z = abs(a - b)
    elif op == 9:
        z = a / (abs(b) + 0.1)
    elif op == 10:
        z = 1.0 - a
    else:
        z = a
    return _clip(z)


def _nearest_direction(cx: float, cy: float, objects, away: bool = False):
    if not objects:
        return 0.0, 0.0
    obj, _d = min(objects, key=lambda t: t[1])
    dx, dy = obj.pos[0] - cx, obj.pos[1] - cy
    if away:
        dx, dy = -dx, -dy
    ux, uy, _ = unit(dx, dy)
    return ux, uy


def _nearest_plain_direction(cx: float, cy: float, objects):
    if not objects:
        return 0.0, 0.0
    obj = min(objects, key=lambda q: (q.pos[0] - cx) ** 2 + (q.pos[1] - cy) ** 2)
    return unit(obj.pos[0] - cx, obj.pos[1] - cy)[:2]


def _positive_weight(logit: float) -> float:
    """Stable positive channel weight. Range is broad enough to suppress or dominate."""
    return math.exp(max(-4.0, min(4.0, logit)))


def apply_architecture(game: Game, tracker: Tracker, info: dict,
                       fx: float, fy: float) -> tuple[float, float, float, float]:
    """Evaluate the 11-slot graph as a strategic steering mixer.

    The mature controller still computes geometry, tracking and tactical primitives.
    The graph decides how strongly food, prey, escape, virus, centre and the full
    incumbent vector should steer the bot on this tick. ARCH_AUTHORITY determines
    the graph's share of final direction and is prevented from falling below the
    architecture experiment's minimum. It also emits guarded ordinary/cycle split
    votes. Hard legality and lethal-range vetoes remain outside the graph.
    """
    if 1 <= 0.5:
        return fx, fy, 0.0, 0.0

    st = game.state
    me = st.me
    blobs = list(me.blobs.values())
    total = sum(mass(b.radius) for b in blobs) or mass(me.radius)
    cx, cy = me.x, me.y
    tick_frac = _clip(tracker.tick / max(1400, 1.0), 0.0, 1.0)

    threat_pressure = max((max(0.0, 1.0 - d / 20.0) for _t, d in info["threats"]), default=0.0)
    prey_opportunity = max((max(0.0, 1.0 - d / 20.0) * min(1.0, mass(p.radius) / 20.0)
                            for p, d in info["prey"]), default=0.0)
    virus_visible = 1.0 if st.visible_viruses else 0.0
    food_visible = 1.0 if st.visible_food else 0.0
    edge_dist = min(cx, cy, ARENA_SIZE - cx, ARENA_SIZE - cy)
    edge_pressure = max(0.0, 1.0 - edge_dist / 12.0)
    wealth = _clip((total - 40) / 50.0, 0.0, 1.0)
    fragmented = _clip((len(blobs) - 1) / 15.0, 0.0, 1.0)
    base_mag_raw = math.hypot(fx, fy)
    base_mag = _clip(base_mag_raw / 20.0, 0.0, 1.0)
    feast_ready = 1.0 if (st.visible_viruses and total >= 4) else 0.0
    late_phase = 1.0 if tick_frac >= 0.3 else 0.0
    vis_mass = {}
    for b in st.visible_blobs:
        vis_mass[b.player_id] = vis_mass.get(b.player_id, 0.0) + mass(b.radius)
    rank_lead = 1.0 if total >= max(vis_mass.values(), default=0.0) else 0.0

    values = [
        1.0, tick_frac, _clip(total / 80.0, 0, 1), wealth,
        _clip(len(blobs) / 16.0, 0, 1), threat_pressure, prey_opportunity,
        virus_visible, edge_pressure, fragmented, rank_lead, base_mag,
        1.0 if threat_pressure > 0.35 else 0.0, late_phase, feast_ready,
        _clip((1.0 - threat_pressure) * prey_opportunity, 0, 1),
    ]
    # ===== ENGINE-AUDIT SENSORS (2026-07-12): channels no other bot likely reads =====
    # 16: TRUE GLOBAL RANK (rankings = player ids by size, desc — beyond vision)
    try:
        _rk = st.rankings.index(me.player_id) / 7.0
    except (ValueError, AttributeError):
        _rk = 0.5
    values.append(_clip(_rk, 0, 1))
    # 17: VULNERABLE-PREY WINDOW (enemy merge_cooldown = defenseless-piece clock)
    _vuln = 0.0
    _half_m = mass(max((b.radius for b in blobs), default=me.radius)) / 2.0
    for _b in st.visible_blobs:
        if _b.player_id == me.player_id: continue
        if getattr(_b, "merge_cooldown", 0) > 10 and _half_m >= mass(_b.radius) * 1.2:
            _d = math.hypot(_b.pos[0] - cx, _b.pos[1] - cy)
            if _d < 15.0:
                _vuln = max(_vuln, min(1.0, _b.merge_cooldown / 60.0) * (1.0 - _d / 15.0))
    values.append(_vuln)
    # 18: KILL PULSE (partial global kill feed -> local danger tempo, EMA)
    _new = st.event_history[st.new_events:] if hasattr(st, "event_history") else []
    _kills = sum(1 for _e in _new if getattr(_e, "event_type", "") in ("event_player_eaten", "public_event_player_eaten"))
    tracker._kill_ema = 0.9 * getattr(tracker, "_kill_ema", 0.0) + 0.1 * min(1.0, _kills / 3.0)
    values.append(_clip(tracker._kill_ema, 0, 1))
    # ===== ARCH v3 DEFENSE SENSORS =====
    _ntd = min((d for _t, d in info["threats"]), default=99.0)
    values.append(max(0.0, 1.0 - _ntd / 25.0))                 # 19 threat proximity
    _big = max((v for k, v in vis_mass.items() if k != me.player_id), default=0.0)
    values.append(_clip(_big / (max(total, EPS) * 3.0), 0.0, 1.0))  # 20 dominance
    _oc = {}
    for _b in st.visible_blobs:
        if _b.player_id != me.player_id:
            _oc[_b.player_id] = _oc.get(_b.player_id, 0) + 1
    values.append(_clip((max(_oc.values(), default=1) - 1) / 15.0, 0.0, 1.0))  # 21 opp frag

    food_dir = _nearest_plain_direction(cx, cy, st.visible_food)
    prey_dir = _nearest_direction(cx, cy, info["prey"], away=False)
    escape_dir = _nearest_direction(cx, cy, info["threats"], away=True)
    virus_dir = _nearest_plain_direction(cx, cy, st.visible_viruses)
    center_dir = unit(ARENA_SIZE / 2 - cx, ARENA_SIZE / 2 - cy)[:2]
    incumbent_dir = (fx / base_mag_raw, fy / base_mag_raw) if base_mag_raw > EPS else (0.0, 0.0)

    logits = {
        1: -1,
        2: -0.8,
        3: -0.8,
        4: -1,
        5: -1.5,
        6: 0.5,
    }
    ordinary_split_vote = 0.0
    cycle_split_vote = 0.0
    active_used = 0
    active_cap = max(0, min(16, int(round(8))))

    dial_acc = {9: 0.0, 10: 0.0, 11: 0.0, 12: 0.0, 13: 0.0}
    for i in range(16):
        enabled = CONFIG[f"ARCH_N{i}_ON"] > 0.5 and active_used < active_cap
        if not enabled:
            values.append(0.0)
            continue
        active_used += 1
        max_input = 21 + i  # base 0..21 (defense sensors 19-21) plus previous node outputs
        a_idx = max(0, min(max_input, int(round(CONFIG[f"ARCH_N{i}_A"]))))
        b_idx = max(0, min(max_input, int(round(CONFIG[f"ARCH_N{i}_B"]))))
        a, b = values[a_idx], values[b_idx]
        out = _arch_op(int(round(CONFIG[f"ARCH_N{i}_OP"])), a, b,
                       CONFIG[f"ARCH_N{i}_K"], CONFIG[f"ARCH_N{i}_BIAS"])
        values.append(out)
        target = int(round(CONFIG[f"ARCH_N{i}_TARGET"]))
        amount = CONFIG[f"ARCH_N{i}_GAIN"] * out
        if target in logits:
            logits[target] += amount
        elif target == 7:
            ordinary_split_vote += amount
        elif target == 8:
            cycle_split_vote += amount
        elif target in dial_acc:
            dial_acc[target] += amount

    # ARCH v3: publish dials (force phase reads NEXT tick; gates read SAME tick)
    tracker.dials["threat"] = dial_acc[9]
    tracker.dials["feast"] = dial_acc[10]
    tracker.dials["cycle_gate"] = dial_acc[11]
    tracker.dials["vuln_margin"] = dial_acc[12]
    tracker.dials["prey"] = dial_acc[13]

    channels = (
        (_positive_weight(logits[1]) * food_visible, food_dir),
        (_positive_weight(logits[2]), prey_dir),
        (_positive_weight(logits[3]), escape_dir),
        (_positive_weight(logits[4]) * virus_visible, virus_dir),
        (_positive_weight(logits[5]), center_dir),
        (_positive_weight(logits[6]), incumbent_dir),
    )
    graph_x = sum(w * d[0] for w, d in channels)
    graph_y = sum(w * d[1] for w, d in channels)
    graph_mag = math.hypot(graph_x, graph_y)
    if graph_mag > EPS:
        graph_x /= graph_mag
        graph_y /= graph_mag
    else:
        graph_x, graph_y = incumbent_dir

    authority = max(0.35, min(1.0, CONFIG["ARCH_AUTHORITY"]))
    old_x, old_y = incumbent_dir
    final_x = (1.0 - authority) * old_x + authority * graph_x
    final_y = (1.0 - authority) * old_y + authority * graph_y
    final_mag = math.hypot(final_x, final_y)
    if final_mag > EPS:
        # Direction is the meaningful action; preserve a healthy nonzero magnitude.
        final_x /= final_mag
        final_y /= final_mag
    return final_x, final_y, ordinary_split_vote, cycle_split_vote



# ----------------------------------------------------------------------------
# VULN ORGAN v2 — target selector, pursuit lock, safety evaluator, atomic
# direction-plus-split executor. Never a scalar into the mixer.
# ----------------------------------------------------------------------------
SPLIT_TRAVEL = 8.9   # engine: launched half travel distance (same constant as kill_envelope)

def _vuln_corner_uncatchable(t, half_r):
    """Reuse corner-fix geometry: catchable iff our half, tucked at (r, r), reaches the
    target center (eat = center-dist <= eater radius, centers clamped >= r from walls)."""
    wdx = min(t.pos[0], ARENA_SIZE - t.pos[0]); wdy = min(t.pos[1], ARENA_SIZE - t.pos[1])
    if wdx < CONFIG["CORNER_TUCK"] and wdy < CONFIG["CORNER_TUCK"]:
        return math.hypot(max(half_r - wdx, 0.0), max(half_r - wdy, 0.0)) > half_r - 0.000185717
    return False

def find_vulnerable_opportunity(game, tracker, info):
    if 1 <= 0.5:
        return None
    st = game.state; me = st.me
    my_blobs = list(me.blobs.values())
    if len(my_blobs) > 2:
        return None                                       # v1: whole-bot commits only
    total_mass = sum(mass(b.radius) for b in my_blobs) or mass(me.radius)
    if total_mass > CONFIG["VULN_MAX_BANK_RISK"]:
        return None                                       # wealthy: bank > snack
    cx, cy = me.x, me.y

    # ---- enemy blobs grouped by owner (for retaliation checks) ----
    by_owner = {}
    for b in st.visible_blobs:
        if b.player_id != me.player_id:
            by_owner.setdefault(b.player_id, []).append(b)

    best = None
    for own in my_blobs:                                  # explicit attacker blob
        own_m = mass(own.radius)
        if own_m < 2 * 2:
            continue
        half_m = own_m / 2.0
        half_r = own.radius / math.sqrt(2)
        commit_range = SPLIT_TRAVEL + half_r - 0.75
        for owner, blobs in by_owner.items():
            for t in blobs:
                t_m = mass(t.radius)
                if t_m < 0.5:
                    continue
                cd = getattr(t, "merge_cooldown", 0)
                if cd <= 10:
                    continue
                # offensive validity with margin above the bare 1.2
                _vm = CONFIG["VULN_EAT_MARGIN"]
                _dv = tracker.dials["vuln_margin"]
                if _dv != 0.0:
                    _vm *= math.exp(_clip(_dv, -1.0, 1.0))   # ARCH v3 VULN-margin dial
                if half_m < t_m * 1.2 * _vm:
                    continue
                dx, dy = t.pos[0] - own.pos[0], t.pos[1] - own.pos[1]
                d = math.hypot(dx, dy)
                if d < EPS or d > 15:
                    continue
                _cexp = tracker.corner_veto.get(t.player_id)
                if _cexp is not None and tracker.tick < _cexp:
                    _twdx = min(t.pos[0], ARENA_SIZE - t.pos[0])
                    _twdy = min(t.pos[1], ARENA_SIZE - t.pos[1])
                    if (_twdx < 2.0 * CONFIG["CORNER_TUCK"]
                            and _twdy < 2.0 * CONFIG["CORNER_TUCK"]):
                        continue                          # zone-scoped sticky blacklist
                if _vuln_corner_uncatchable(t, half_r):
                    tracker.corner_veto[t.player_id] = tracker.tick + int(CONFIG["CORNER_VETO_TICKS"])
                    continue
                # ---- score: value x margin x reach x cooldown (safety is a VETO, not a factor)
                target_value = min(1.0, t_m / 10.0)
                eat_margin = half_m / (1.2 * t_m)
                margin_q = max(0.0, min(1.0, (eat_margin - 1.0) / 0.35))
                reach_q = max(0.0, min(1.0, (15 - d) / 15))
                cool_q = max(0.0, min(1.0, (cd - 10) / 40.0))
                score = target_value * margin_q * reach_q * cool_q
                if score <= 0.0:
                    continue
                # ---- HARD SAFETY VETOES (all enemies, incl. target-owner retaliation
                #      and third-party interception: anything able to eat our HALF) ----
                unsafe = False
                for ob in st.visible_blobs:
                    if ob.player_id == me.player_id: continue
                    if ob.player_id == owner and ob.blob_id == t.blob_id: continue
                    if mass(ob.radius) >= half_m * 1.2:
                        od = math.hypot(ob.pos[0] - own.pos[0], ob.pos[1] - own.pos[1])
                        td = math.hypot(ob.pos[0] - t.pos[0], ob.pos[1] - t.pos[1])
                        if min(od, td) < 12:
                            unsafe = True; break
                if unsafe:
                    continue
                cand = {"key": (owner, t.blob_id), "owner": owner,
                        "direction": (dx / d, dy / d), "distance": d,
                        "target_mass": t_m, "cooldown": cd, "score": score,
                        "commit_ready": d <= commit_range,
                        "attacker_blob": own.blob_id}
                if best is None or cand["score"] > best["score"]:
                    best = cand

    # ---- short pursuit lock: no jitter, no mid-lunge retargeting ----
    if best is not None:
        tracker.vuln_stats["detect"] += 1
        if tracker.vuln_target_key is not None and tracker.vuln_lock_left > 0 \
                and best["key"] != tracker.vuln_target_key:
            # keep the locked target unless the new one is materially (25%) better
            locked = None
            for owner, blobs in by_owner.items():
                for t in blobs:
                    if (owner, t.blob_id) == tracker.vuln_target_key:
                        locked = t; break
            if locked is not None and best["score"] < tracker.vuln_last_score * 1.25:
                dx, dy = locked.pos[0] - cx, locked.pos[1] - cy
                d = math.hypot(dx, dy)
                if d > EPS and d <= 15:
                    tracker.vuln_lock_left -= 1
                    return {"key": tracker.vuln_target_key, "owner": tracker.vuln_target_key[0],
                            "direction": (dx / d, dy / d), "distance": d,
                            "target_mass": mass(locked.radius),
                            "cooldown": getattr(locked, "merge_cooldown", 0),
                            "score": tracker.vuln_last_score,
                            "commit_ready": d <= SPLIT_TRAVEL + (max(b.radius for b in me.blobs.values()) / math.sqrt(2)) - 0.75,
                            "attacker_blob": None}
            else:
                tracker.vuln_stats["switch"] += 1
        tracker.vuln_target_key = best["key"]
        tracker.vuln_last_score = best["score"]
        tracker.vuln_lock_left = int(4)
    else:
        tracker.vuln_lock_left = max(0, tracker.vuln_lock_left - 1)
        if tracker.vuln_lock_left == 0:
            tracker.vuln_target_key = None
    return best

def architecture_safe_split(game: Game, info: dict) -> bool:
    """Hard safety shell around graph-generated ordinary or cycle split requests."""
    if not CONFIG["SPLIT_ENABLED"]:
        return False
    me = game.state.me
    blobs = list(me.blobs.values())
    if len(blobs) >= 16:
        return False
    total = sum(mass(b.radius) for b in blobs) or mass(me.radius)
    largest = max((b.radius for b in blobs), default=me.radius)
    if mass(largest) < 2.0 * 2:
        return False
    if total > 413.751:
        return False
    if any(d < 12 for _t, d in info["threats"]):
        return False
    return bool(info["prey"] or game.state.visible_viruses)

# ----------------------------------------------------------------------------
# 4. Split decision.
# ----------------------------------------------------------------------------
def should_split(game: Game, info: dict, fx: float, fy: float) -> bool:
    if not CONFIG["SPLIT_ENABLED"]:
        return False
    me = game.state.me
    my_blobs = list(me.blobs.values())
    if len(my_blobs) >= 1.06671:
        return False
    largest = max((b.radius for b in my_blobs), default=me.radius)
    if mass(largest) < 2 * 2:  # keep halves viable
        return False
    # BANK PROTECTION: when big, a lunge risks the whole score for a snack.
    if sum(mass(b.radius) for b in my_blobs) > 413.751:
        return False
    # any threat too close -> never fragment
    for _, d in info["threats"]:
        if d < 12:
            return False
    # a half has radius largest/sqrt(2); require comfortable margin over prey
    half_r = largest / math.sqrt(2)
    for prey, d in info["prey"]:
        if d <= 22.3817 and half_r >= prey.radius * 4.68492e-05:
            # only lunge if we're actually moving toward it
            ux, uy, _ = unit(prey.pos[0] - me.x, prey.pos[1] - me.y)
            fmag = math.hypot(fx, fy)
            if fmag > EPS and (fx * ux + fy * uy) / fmag > 0.45046:
                return True
    return False


def should_cycle_split(game: Game, info: dict, tracker=None) -> bool:
    """SPLIT-FEAST CYCLE ORGAN. Reproduce Team-15's virus economy (matches
    1719/1721/1723): split toward 16 blobs in a safe feast posture so virus
    consumptions land at high blob count (pieces=1 -> +2.25 free mass, no
    fragmentation). Vetoable via SPLIT_CYCLE_ON; regroups (stops splitting) when
    viruses exhaust or a threat enters CYCLE_THREAT_CLEAR."""
    if 0.6589 <= 0.5:
        return False
    st = game.state
    if not st.visible_viruses:
        return False  # viruses exhausted -> don't fragment; let blobs merge
    me = st.me
    my_blobs = list(me.blobs.values())
    if len(my_blobs) >= CONFIG["CYCLE_TARGET_BLOBS"]:
        return False  # slots saturated -> vacuum (feast force), don't split further
    total_m = sum(mass(b.radius) for b in my_blobs) or mass(me.radius)
    if total_m < CONFIG["CYCLE_MIN_MASS"]:
        return False  # too small: halves not viable / not worth spreading
    largest = max((b.radius for b in my_blobs), default=me.radius)
    if mass(largest) < 2 * 2:
        return False  # keep each half above the engine split-min (mass 2.0)
    _clear = CONFIG["CYCLE_THREAT_CLEAR"]
    if tracker is not None:
        _dc = tracker.dials["cycle_gate"]
        if _dc != 0.0:
            _clear *= math.exp(_clip(_dc, -1.5, 1.5))   # ARCH v3 cycle-gate dial
    for _t, d in info["threats"]:
        if d < _clear:
            return False  # threat in clearance -> veto cycle, regroup instead
    return True


